targets.expr:
topk(20, 
  sum by (attributes_user_email) (
    sum_over_time(
      {service_name=~"claude-code|cowork"} 
      | json 
      | body="claude_code.api_request" 
      | __error__=""
      ${model:pipe} 
      ${effort:pipe} 
      ${query_source:pipe} 
      ${terminal_type:pipe}
      | label_format total_tokens=`{{add .attributes_input_tokens .attributes_output_tokens}}`
      | unwrap total_tokens [$__range]
    )
  )
)
